body:
This commit adds the ESI CPP API as well as implementing support for the cosim (Capn'Proto) backend.

The API is somewhat inspired by the python API, wherein `circt/include/circt/Dialect/ESI/Runtime/esi.h` defines the interface that backends must adhere to - backends then implement the given ports. Tests can then be written using a template parameter for the backend, with the idea that that backend will be interchangeable from i.e. the cosim backend, FPGA backend,....

I've got the `esi_ram.cpp` test working locally and just need to make sure that things work as expected in CI...

Example generated API for `esi_ram.cpp`:

```C++
#pragma once

// The ESI C++ API relies on the refl-cpp library for type introspection. This must be provided by the user.
// See https://github.com/veselink1/refl-cpp 
#include "refl.hpp"

#include <cstdint>
#include "esi/backends/cosim/capnp.h"

// Include the generated Cap'nProto schema header. This must defined by the build system.
#include ESI_COSIM_CAPNP_H


namespace esi {
namespace runtime {

class ESITypes {
public:
  struct Struct16871797234873963366 {
    // Data members:
    uint8_t address;	// MLIR type is i3
    uint64_t data;	// MLIR type is i64

    // Spaceship operator for all-things comparison
    auto operator<=>(const Struct16871797234873963366 &other) const = default;

    // Stream operator
    friend std::ostream &operator<<(std::ostream &os, const Struct16871797234873963366 &val) {
      os << "Struct16871797234873963366(";
      os << "address: ";
      os << (uint32_t)val.address;
      os << ", ";
      os << "data: ";
      os << val.data;
      os << ")";
      return os;
    }

    // Cap'nProto type which this ESI type maps to
    using CPType = ::Struct16871797234873963366;
  };

  struct I3 {
    // Data members:
    uint8_t i;	// MLIR type is i3

    // Unary types have convenience constructors
    I3() = default;
    I3(uint8_t i) : i(i) {}

    // Unary types have convenience conversion operators
    operator uint8_t    () const { return i; }

    // Spaceship operator for all-things comparison
    auto operator<=>(const I3 &other) const = default;

    // Stream operator
    friend std::ostream &operator<<(std::ostream &os, const I3 &val) {
      os << "I3(";
      os << "i: ";
      os << (uint32_t)val.i;
      os << ")";
      return os;
    }

    // Cap'nProto type which this ESI type maps to
    using CPType = ::I3;
  };

  struct I64 {
    // Data members:
    uint64_t i;	// MLIR type is i64

    // Unary types have convenience constructors
    I64() = default;
    I64(uint64_t i) : i(i) {}

    // Unary types have convenience conversion operators
    operator uint64_t    () const { return i; }

    // Spaceship operator for all-things comparison
    auto operator<=>(const I64 &other) const = default;

    // Stream operator
    friend std::ostream &operator<<(std::ostream &os, const I64 &val) {
      os << "I64(";
      os << "i: ";
      os << val.i;
      os << ")";
      return os;
    }

    // Cap'nProto type which this ESI type maps to
    using CPType = ::I64;
  };

  struct I0 {
    // Data members:
    // Zero-width field: void i;	// MLIR type is i0

    // Unary types have convenience constructors
    I0() = default;
    // Spaceship operator for all-things comparison
    auto operator<=>(const I0 &other) const = default;

    // Stream operator
    friend std::ostream &operator<<(std::ostream &os, const I0 &val) {
      os << "I0(";
      os << ")";
      return os;
    }

    // Cap'nProto type which this ESI type maps to
    using CPType = ::UntypedData;
  };

};

template <typename TBackend>
class MemComms : public esi::runtime::Module<TBackend> {
    using Port = esi::runtime::Port<TBackend>;
public:
  // Port type declarations.
  using Twrite = esi::runtime::WritePort</*writeType=*/ ESITypes::Struct16871797234873963366, TBackend>;
  using TwritePtr = std::shared_ptr<Twrite>;

  using Tread = esi::runtime::ReadWritePort</*readType=*/ ESITypes::I3, /*writeType=*/ ESITypes::I64, TBackend>;
  using TreadPtr = std::shared_ptr<Tread>;

  using Tloopback = esi::runtime::ReadWritePort</*readType=*/ ESITypes::Struct16871797234873963366, /*writeType=*/ ESITypes::Struct16871797234873963366, TBackend>;
  using TloopbackPtr = std::shared_ptr<Tloopback>;

  // Constructor initializes each endpoint.
  MemComms(TwritePtr write, TreadPtr read, TloopbackPtr loopback)
    // Initialize base class with knowledge of all endpoints.
    : esi::runtime::Module<TBackend>({write, read, loopback}),
    // Initialize each individual endpoint handle.
    write(write), read(read), loopback(loopback) {}

  // Endpoint handles
  TwritePtr write;
  TreadPtr read;
  TloopbackPtr loopback;
};

template <typename TBackend>
class DeclareRandomAccessMemory : public esi::runtime::Module<TBackend> {
    using Port = esi::runtime::Port<TBackend>;
public:
  // Port type declarations.
  using Twrite = esi::runtime::ReadWritePort</*readType=*/ ESITypes::I0, /*writeType=*/ ESITypes::Struct16871797234873963366, TBackend>;
  using TwritePtr = std::shared_ptr<Twrite>;

  using Tread = esi::runtime::ReadWritePort</*readType=*/ ESITypes::I64, /*writeType=*/ ESITypes::I3, TBackend>;
  using TreadPtr = std::shared_ptr<Tread>;

  // Constructor initializes each endpoint.
  DeclareRandomAccessMemory(TwritePtr write, TreadPtr read)
    // Initialize base class with knowledge of all endpoints.
    : esi::runtime::Module<TBackend>({write, read}),
    // Initialize each individual endpoint handle.
    write(write), read(read) {}

  // Endpoint handles
  TwritePtr write;
  TreadPtr read;
};

template <typename TBackend>
class BSP : public esi::runtime::Module<TBackend> {
    using Port = esi::runtime::Port<TBackend>;
public:
  // Port type declarations.
  using Twrite = esi::runtime::WritePort</*writeType=*/ ESITypes::Struct16871797234873963366, TBackend>;
  using TwritePtr = std::shared_ptr<Twrite>;

  using Tread = esi::runtime::ReadWritePort</*readType=*/ ESITypes::I3, /*writeType=*/ ESITypes::I64, TBackend>;
  using TreadPtr = std::shared_ptr<Tread>;

  using Tloopback = esi::runtime::ReadWritePort</*readType=*/ ESITypes::Struct16871797234873963366, /*writeType=*/ ESITypes::Struct16871797234873963366, TBackend>;
  using TloopbackPtr = std::shared_ptr<Tloopback>;

  // Constructor initializes each endpoint.
  BSP(TwritePtr write, TreadPtr read, TloopbackPtr loopback)
    // Initialize base class with knowledge of all endpoints.
    : esi::runtime::Module<TBackend>({write, read, loopback}),
    // Initialize each individual endpoint handle.
    write(write), read(read), loopback(loopback) {}

  // Endpoint handles
  TwritePtr write;
  TreadPtr read;
  TloopbackPtr loopback;
};

template <typename TBackend>
class top {
public:
  std::unique_ptr<BSP<TBackend>> bsp;
  top(TBackend& backend) {
    // BSP initialization.
    auto Top_read = std::make_shared<esi::runtime::ReadWritePort</*readType=*/ ESITypes::I3, /*writeType=*/ ESITypes::I64, TBackend>>(std::vector<std::string>{"Top", "read"}, backend, "cosim");
    auto Top_loopback = std::make_shared<esi::runtime::ReadWritePort</*readType=*/ ESITypes::Struct16871797234873963366, /*writeType=*/ ESITypes::Struct16871797234873963366, TBackend>>(std::vector<std::string>{"Top", "loopback"}, backend, "cosim");
    auto Top_write = std::make_shared<esi::runtime::WritePort</*writeType=*/ ESITypes::Struct16871797234873963366, TBackend>>(std::vector<std::string>{"Top", "write"}, backend, "cosim");
    bsp = std::make_unique<BSP<TBackend>>(Top_write, Top_read, Top_loopback);
    bsp->init();
  }
};

} // namespace runtime
} // namespace esi

// ESI dynamic reflection support
REFL_AUTO (
  type(esi::runtime::ESITypes::Struct16871797234873963366)  
, field(address)  
, field(data)
)
REFL_AUTO (
  type(esi::runtime::ESITypes::I3)  
, field(i)
)
REFL_AUTO (
  type(esi::runtime::ESITypes::I64)  
, field(i)
)
REFL_AUTO (
  type(esi::runtime::ESITypes::I0)  
//, field(i)
)
